import { test, expect } from '@playwright/test';

test('Amazon SG - Add product to cart and validate cart page', async ({ page }) => {
  // 1. Launch browser → Amazon SG.
  await page.goto('https://www.amazon.sg/');
  await expect(page).toHaveURL(/amazon\.sg/);

  // 2. Add product to cart.
  // Search for a product (e.g., "laptop")
  const searchBox = page.getByRole('combobox', { name: /search/i });
  await searchBox.fill('laptop');
  await searchBox.press('Enter');

  // Wait for search results to load
  const firstProduct = page.locator('div.s-main-slot div[data-component-type="s-search-result"]').first();
  await expect(firstProduct).toBeVisible({ timeout: 10000 });

  // Click on the first product link
  const productLink = firstProduct.locator('h2 a');
  await productLink.click();

  // Wait for product detail page to load
  await expect(page).toHaveURL(/\/dp\//, { timeout: 10000 });

  // Click "Add to Cart" button
  const addToCartButton = page.getByRole('button', { name: /add to cart/i });
  await expect(addToCartButton).toBeVisible({ timeout: 10000 });
  await addToCartButton.click();

  // Wait for cart confirmation (e.g., "Added to Cart" text)
  const addedToCartText = page.getByText('Added to Cart', { exact: false });
  await expect(addedToCartText).toBeVisible({ timeout: 10000 });

  // 3. Click cart icon (id="nav-cart").
  const cartIcon = page.locator('#nav-cart');
  await expect(cartIcon).toBeVisible({ timeout: 10000 });
  await cartIcon.click();

  // 4. Validate cart page loads.
  await expect(page).toHaveURL(/cart\.amazon\.sg/);
  const cartHeader = page.getByRole('heading', { name: /shopping cart/i });
  await expect(cartHeader).toBeVisible({ timeout: 10000 });

  // 5. Close browser.
  // (Playwright test runner handles browser close automatically)
});
